'use client';

import type * as React from 'react';

import {cn} from '@/lib/utils';

import {Progress as ProgressPrimitive} from 'radix-ui';

/**
 * Displays an indicator showing the completion progress of a task, typically displayed as a progress bar.
 *
 * ### Component Props
 *
 * See [Progress props](https://www.radix-ui.com/primitives/docs/components/progress) documentation for full details.
 *
 * | Prop            | Type                              | Default |
 * | :-------------- | :-------------------------------- | :------ |
 * | _asChild_       | `boolean`                         | `false` |
 * | _value_         | `number \| null`                  | -       |
 * | _max_           | `number`                          | -       |
 * | _getValueLabel_ | `(value: number, max: number) => string` | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Progress value={66} />
 * ```
 */
function Progress({
  className,
  value,
  ...props
}: React.ComponentProps<typeof ProgressPrimitive.Root>) {
  return (
    <ProgressPrimitive.Root
      data-slot="progress"
      value={value}
      className={cn(
        'relative flex h-1.5 w-full items-center overflow-x-hidden rounded-full bg-muted',
        className
      )}
      {...props}
    >
      <ProgressPrimitive.Indicator
        data-slot="progress-indicator"
        className="size-full flex-1 bg-primary transition-all ease-default"
        style={{transform: `translateX(-${100 - (value || 0)}%)`}}
      />
    </ProgressPrimitive.Root>
  );
}

export {Progress};
